import{_ as a,o as r,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"9. Weekend Work","description":"","frontmatter":{"title":"9. Weekend Work","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/hours-of-work/9-weekend-work.md","filePath":"ebas/has-managers-admin/managers-admin/hours-of-work/9-weekend-work.md"}'),s={name:"ebas/has-managers-admin/managers-admin/hours-of-work/9-weekend-work.md"};function o(d,e,i,l,m,h){return r(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_9-weekend-work" tabindex="-1">9. Weekend Work <a class="header-anchor" href="#_9-weekend-work" aria-label="Permalink to &quot;9. Weekend Work&quot;">​</a></h1><p><strong>9.1</strong> All rostered time of ordinary duty performed between midnight on Friday and Midnight on Sunday will be paid for at the rate of 150% (based on 1/38th of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>)</p><p><strong>9.2</strong> Where Employees are required to carry out duties on a Saturday or Sunday in excess of the weeks work, such duties will be paid for at the rate of 200% (based on 1/38ths of the weekly salary set out in <a href="/eba/ebas/has-managers-admin/schedules/3b-wage-rates-managers-and-administrative-workers.html">Schedule 3B</a>).</p><p>Plain language terms: weekend penalty, weekend loading, Saturday rate, Sunday rate.</p>',4)])])}const w=a(s,[["render",o]]);export{u as __pageData,w as default};
